import{_ as e,o as t,c as b,j as r,a as p,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.10.物品综述、装备栏位","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/1.核心规则/1.10.物品综述、装备栏位.md","filePath":"1.基础规则/1.核心规则/1.10.物品综述、装备栏位.md"}'),n={name:"1.基础规则/1.核心规则/1.10.物品综述、装备栏位.md"};function s(o,a,d,l,h,i){return t(),b("div",null,[...a[0]||(a[0]=[r("h1",{id:"_1-10-物品综述、装备栏位",tabindex:"-1"},[p("1.10.物品综述、装备栏位 "),r("a",{class:"header-anchor",href:"#_1-10-物品综述、装备栏位","aria-label":'Permalink to "1.10.物品综述、装备栏位"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001A")])])],-1),_('<h1 id="物品综述、装备栏位" tabindex="-1">物品综述、装备栏位 <a class="header-anchor" href="#物品综述、装备栏位" aria-label="Permalink to &quot;物品综述、装备栏位&quot;">​</a></h1><p>物品综述<br> 对于物品而言，它的购买与使用是最基础的互动方式。对于一个轮回者对其所进行的本质认知而言，它在本质上大致可分为自然物品、科技物品、神话物品、特异物品和魔法物品五种。详见<a href="./资源与本质.htm.html">资源与本质</a>一节。<br> 多件使用方式相同的物品在通常情况下并不会同时提供多倍增益（特指同种），而在另一种意义上，一件物品在生效时的唯一性基于装备栏位决定。<br> 物品的本质，顾名思义，就是一种对应的来源形式，它由何种形式打造，便拥有何种形式的来源。在本质上，这种来源并不会产生更多的影响，但在特殊情况下，这种来源会起到作用（或反作用）<br> 一件物品的分类不一定是奇物，也有可能是物品、武器、防具或载具等分类，它会拥有自身的等级，人物能否使用一件物品的并不会因物品的等级高于人物当前等级而受限，物品的等级只是用于标注它的当前等级而不是为了设置更多基础部分上的限制。<br> 选开：当一件低等级武器试图释放高于它当前等级的招式时，这次尝试是必定会失败的。</p><hr><p>物品的生效、使用、所有权<br> 一件物品效果的生效与否通常与以下行为有关：<br> 1、持有/持用:具有这一类描述生效的物品通常需要角色以肢体持握才可发挥该物品的效果。如果人物持有了多个此类物品，在没有相关强化的前提下只能有一个物品生效。最典型的，人物双手持有两把武器，在没有相关强化的前提下，同时只能享有其中一把武器带来的好处。<br> 2、佩戴/穿戴：这一类描述生效的物品通常需要角色将其装备在一个装备栏位才能生效。<br> 3、基于：这一类描述生效的物品通常需要基于某些物品上才能生效，例如枪械的配件、铠甲上的加固装置。<br> 4、使用：对于武器/法杖此类物品而言，它们的效果都需要人物以它们默认的使用方式进行使用才能生效。例如：你将一柄法杖用于投掷，这次攻击不能附带法杖所具有的特效与法术强度，因为该武器的使用方式并非本应具有的使用方式。</p><p>所有权：轮回者购买的所有物品默认只有轮回者本人与其随从、召唤物、载具可以使用，除非资源特别声明了这一物品会如何失去所有权，否则其他拾取该物品的单位无法正常的使用/收纳这一物品。这也意味着若轮回者不具有物品的所有权，将无法把一件属于他人的物品收入自身的储物空间。</p><p>物品栏位<br> 一般情况下，一个物品栏位只能承载一件物品，当然，也不排除有玩家刻意想搭载更多物品的想法，如若此作，则在通常情况下只能同时选择其中一种生效。<br> 人形生物固定装备栏位：<br> 头部-头盔/面具<br> 颈部-护符<br> 上肢-躯干<br> 肩部-斗篷<br> 上肢-双手（特殊的，手部可以同时持有两把合理的武器，但如若无特殊情况，只能在攻击时使用其中一把）<br> 手部-手腕<br> 手部-戒指（特殊的，戒指在生效时最多可以有两枚，分别为左右手佩戴的第一枚戒指）/手套（手套一般成双佩戴，手套和戒指只有一种能同时生效）<br> 腰部-腰带<br> 下肢-躯干<br> 下肢-鞋袜<br> 概念武装/概念物品是特指那些并不具有实体，但仍能发挥它的作用，概念武装/概念物品在装备的归类上仍然会归在那个装备栏位上，仍然占据那个栏位才能生效<br> 饰品（指一些不便归类但是可能存在的细小物件，如耳饰等）</p><p>在身着一种轻甲时，如无特殊说明，则它仅会占据上肢-躯干的物品栏；而在身着一种重甲时，如无特殊说明，则它会同时占据上肢-躯干和下肢-躯干的物品栏。</p><p>多重着甲<br> 如若一名角色试图同时穿着数件盔甲，则以以下方式进行判定此时人物的防御状况<br> 若这些盔甲均为轻甲，则无论如何，均只以最外层的轻甲护甲及效果进行结算，每以此法多套一件，就需额外承受2点力量上的需求。<br> 若这些盔甲均为重甲，则无论如何，均只以最内层的重甲护甲及效果进行结算，每以此法多套一件，就需额外承受2点盔甲减值，且若最内层护甲会提供闪避防御，则失去。<br> 若这些盔甲中轻重皆有，则无论如何，均只以最外层轻甲的效果和最内层重甲的护甲进行结算，每以此法多套一件重甲，就需额外承受2点盔甲减值；每以此法多套一件轻甲，就需额外承受2点力量上的需求。此时，若最内层护甲会提供闪避防御，则失去。<br> 在处于多重着甲状态时，若被击倒，则需整轮动作才能爬起。在处于着重甲状态时，若被击倒，则需标准动作才能爬起。</p><p>注：多重着甲只是为着甲者提供护甲带来的好处，这并不会代表多重着甲会让角色视为同时穿着轻甲和重甲。</p><p>物品的携带<br> 除了人物身穿戴的物品、持有的武器之外，人物还可以随身携带一些物品，携带物品的上限被称为携带物品体积。<br> 人物的通常携带物品体积上限等同于人物的力量属性值，每有1点体积高于/低于5，人物可携带物品的体积上限就增加/减少1点。人物每拥有1点力量上的附加成功就可多携带4体积物品。<br> 人物可以试着携带超出携带物品体积上限的物品，每超出携带物品体积上限1点，人物就在生理属性检定上承受1点器械减值，人物可负荷的超出携带物品体积为人物的耐力属性值，当人物携带超过物品体积上限的物品时，人物至少需要占用一只可用肢体去携带这些物品。<br> 如果人物携带的物品总体积已超过其本体体积的一半及以上，则超出携带的部分很容易就会被他人发现，除非其特别准备了背包等容器空间而不是简单的带在身上。</p><p>武器力量需求<br> 武器力量需求由人物体积与力量综合判断以决定。当人物体积为5，力量为1时，最多可以携带体积为2的武器。此时力量每上升1，携带武器的体积就上升1；体积每上升1，携带武器力量体积也上升1。反之，体积低于5时，每1点低于5的体积将少携带体积为1的武器。<br> 一般而言，武器的力量需求等同于其体积数，因此，当一件武器的体积变少时，其力量需求也将自然随之变少。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=e(n,[["render",s]]);export{f as __pageData,m as default};
